<?php require_once __DIR__.'/../app/bootstrap.php'; if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf(); foreach(['site_name','site_description','rss_fetch_limit','post_article_count','post_interval_minutes','history_retention_days'] as $k)set_setting($k,(string)($_POST[$k]??''));} admin_header('基本設定'); echo'<form method=post><input type=hidden name=csrf value='.csrf_token().'>'; foreach(['site_name'=>'サイト名','site_description'=>'サイト説明','rss_fetch_limit'=>'RSS共通取得件数','post_article_count'=>'livedoor投稿件数','post_interval_minutes'=>'投稿間隔(分)','history_retention_days'=>'投稿履歴保持日数'] as $k=>$l) echo'<label>'.e($l).'<input name='.$k.' value="'.e(setting($k,'')).'"></label>'; echo'<p>ツールRSS配信件数は20件固定です。</p><button>保存</button></form>'; admin_footer();
